import { Component, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { Router } from '@angular/router';
import { Workspace } from '../../core/models';

/**
 * CodeDeck workspaces list — the default authenticated route. Lists the user's
 * workspaces (admins see all), and supports create / rename / delete. Clicking a
 * workspace opens the editor at `/workspaces/:id`.
 *
 * Mock data is held in a `signal<Workspace[]>` per the data contract; the
 * service_agent stage clears it and wires `ApiService.listWorkspaces()` etc.
 */
@Component({
  selector: 'app-workspaces-list',
  standalone: true,
  imports: [CommonModule, FormsModule],
  templateUrl: './workspaces-list.component.html',
  styleUrl: './workspaces-list.component.css',
})
export class WorkspacesListComponent {
  readonly loading = signal(false);
  readonly error = signal<string | null>(null);

  readonly workspaces = signal<Workspace[]>([
    {
      id: 'ws-1',
      ownerId: 'u-dev',
      name: 'Sample Project',
      fileCount: 4,
      updatedAt: '2026-07-11T14:22:00.000Z',
    },
    {
      id: 'ws-2',
      ownerId: 'u-dev',
      name: 'landing-page',
      fileCount: 12,
      updatedAt: '2026-07-10T09:05:00.000Z',
    },
    {
      id: 'ws-3',
      ownerId: 'u-dev',
      name: 'api-scripts',
      fileCount: 7,
      updatedAt: '2026-07-08T18:40:00.000Z',
    },
  ]);

  // ---- Create / rename modal state ----
  readonly modalOpen = signal(false);
  readonly editingId = signal<string | null>(null);
  draftName = '';

  constructor(private router: Router) {}

  open(ws: Workspace): void {
    this.router.navigate(['/workspaces', ws.id]);
  }

  newWorkspace(): void {
    this.editingId.set(null);
    this.draftName = '';
    this.modalOpen.set(true);
  }

  rename(ws: Workspace, event: Event): void {
    event.stopPropagation();
    this.editingId.set(ws.id);
    this.draftName = ws.name;
    this.modalOpen.set(true);
  }

  closeModal(): void {
    this.modalOpen.set(false);
    this.editingId.set(null);
    this.draftName = '';
  }

  saveModal(): void {
    const name = this.draftName.trim();
    if (!name) return;
    const id = this.editingId();
    if (id) {
      this.workspaces.update((list) =>
        list.map((w) => (w.id === id ? { ...w, name } : w)),
      );
    } else {
      const newWs: Workspace = {
        id: `ws-${Math.round(performance.now())}`,
        ownerId: 'u-dev',
        name,
        fileCount: 0,
        updatedAt: new Date(2026, 6, 12).toISOString(),
      };
      this.workspaces.update((list) => [newWs, ...list]);
    }
    this.closeModal();
  }

  remove(ws: Workspace, event: Event): void {
    event.stopPropagation();
    if (!confirm(`Delete workspace “${ws.name}” and all its files? This cannot be undone.`)) {
      return;
    }
    this.workspaces.update((list) => list.filter((w) => w.id !== ws.id));
  }
}
